"use strict";(self.webpackChunkavstudio_docs=self.webpackChunkavstudio_docs||[]).push([[5259],{87247:e=>{e.exports=JSON.parse('{"tag":{"label":"avstudio","permalink":"/avstudio-docs/tags/avstudio","allTagsPath":"/avstudio-docs/tags","count":43,"items":[{"id":"documentation/user-interface/user-interface","title":"3 User interface","description":"The User Interface of AVgator Studio provides a user-friendly and","permalink":"/avstudio-docs/documentation/user-interface/"},{"id":"about/about","title":"About AVgator Studio (AVstudio)","description":"To create a user interface on HTML5 for a Crestron control system, you","permalink":"/avstudio-docs/about/"},{"id":"documentation/getting-started/2-3-accessing-the-application/2-3-accessing-the-application","title":"Accessing the Application","description":"Log in to AVstudio to begin building and managing your user interfaces. Whether you\'re starting a new project or continuing existing work, this guide walks you through the secure login process.","permalink":"/avstudio-docs/documentation/getting-started/2-3-accessing-the-application/"},{"id":"documentation/working-with-projects/4-3-adding-pages/4-3-adding-pages","title":"Adding Pages to Your Project","description":"After configuring your project settings, the next step is to add pages. Each page represents a distinct screen in your AVstudio interface. In this guide, you\'ll learn how to create a page, select a design paradigm, open the page in the editor, and set its properties and parameters.","permalink":"/avstudio-docs/documentation/working-with-projects/4-3-adding-pages/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-1-alignment/4-4-4-1-alignment","title":"Alignment","description":"The Alignment settings within the Container Options panel control how elements inside a container are arranged and aligned. This section applies to both responsive and adaptive pages and is especially useful for designing flexible layouts that adapt to various screen sizes and orientations.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-1-alignment/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-2-alignment-settings/4-4-2-alignment-settings","title":"Alignment Settings","description":"The Alignment panel lets you control how containers are arranged on the page. This setting affects the overall layout flow and helps you visually align elements based on the orientation or structure of your page.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-2-alignment-settings/"},{"id":"knowledge-base/autonomic/autonomic","title":"Autonomic Mirage Media Server Integration Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/autonomic/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-4-background/4-4-4-4-background","title":"Background","description":"The Background section lets you customize how a container looks visually by adding background colors, blur effects, or images. These settings allow you to define the tone and depth of UI sections, making your layout feel more dynamic and styled.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-4-background/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-3-border/4-4-4-3-border","title":"Border","description":"The Border section allows you to define how the edges of a container appear. You can keep the project\u2019s default styling or override it with custom width, style, color, and radius settings.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-3-border/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-container-options","title":"Container Options","description":"The Container options panel allows you to configure how a specific container behaves and appears on the page. Whether you\'re adjusting layout or applying styles, this panel gives you precise control over container properties.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-3-containers/4-4-3-containers","title":"Containers","description":"In AVstudio, containers define the structure of your interface. They hold elements, apply styling, and help organize how content is displayed. This article introduces the two main types: Global Containers and Page Containers, and explains how they behave on both responsive and adaptive pages.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-3-containers/"},{"id":"documentation/user-interface/3-9-data-sources/3-9-data-sources","title":"Data Sources Overview","description":"The Data Sources section in AVstudio allows you to connect your project to external APIs, WebSocket streams, or local mock data. These sources can be used to feed dynamic content into your pages and components. With support for data transformation, image preloading, and flexible HTTP or WebSocket configurations, data sources make it easy to integrate real-time and remote data into your AVstudio workflows.","permalink":"/avstudio-docs/documentation/user-interface/3-9-data-sources/"},{"id":"documentation/documentation","title":"Documentation","description":"Complete documentation for AV Studio","permalink":"/avstudio-docs/documentation/"},{"id":"knowledge-base/doorbird/doorbird","title":"DoorBird Intercoms Integration Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/doorbird/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-5-elements/4-4-5-elements","title":"Elements","description":"Each container in AVstudio can hold one or more elements. These elements define the actual content or controls inside your layout\u2014such as buttons, sliders, inputs, or embedded widgets.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-5-elements/"},{"id":"documentation/user-interface/3-10-functions/3-10-functions","title":"Functions Overview","description":"The Functions section in AVstudio allows you to define custom JavaScript logic that enhances your project\u2019s interactivity. Functions can be used to manipulate variables, trigger navigation, fetch data, publish signals, and control audio playback. With built-in code snippets, live testing, and support for arguments, functions offer a flexible way to add dynamic behaviors across your application.","permalink":"/avstudio-docs/documentation/user-interface/3-10-functions/"},{"id":"documentation/getting-started/getting-started","title":"Getting Started","description":"Get started with AVstudio","permalink":"/avstudio-docs/documentation/getting-started/"},{"id":"documentation/user-interface/3-7-global-containers/3-7-global-containers","title":"Global Containers Overview","description":"The Global Containers section in AVstudio lets you create persistent, reusable interface blocks that appear across multiple pages. Whether it\u2019s a navigation bar, footer, or overlay, global containers help ensure design consistency while giving you control over placement and visibility on a per-page basis.","permalink":"/avstudio-docs/documentation/user-interface/3-7-global-containers/"},{"id":"documentation/working-with-projects/4-1-creating-projects/4-1-creating-projects","title":"How to Create a Project","description":"There are several ways to start a project in AVstudio. You can create a new one from scratch, duplicate an existing project, or start with a template. This guide walks you through each option.","permalink":"/avstudio-docs/documentation/working-with-projects/4-1-creating-projects/"},{"id":"knowledge-base/how-to/button-with-a-gradient-or-an-image/button-with-a-gradient-or-an-image","title":"How to create button with a gradient","description":"Introduction","permalink":"/avstudio-docs/knowledge-base/how-to/button-with-a-gradient-or-an-image/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-1-initial-page-settings/4-4-1-initial-page-settings","title":"Initial Page Settings","description":"When you open a page in the editor, AVstudio automatically loads the Page Properties view. This is where you configure the basic identity and behavior of the page before adding content or containers.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-1-initial-page-settings/"},{"id":"documentation/Introduction/introduction","title":"Introduction to AVstudio","description":"Welcome to AVstudio\u2014your gateway to designing dynamic and interactive user interfaces with professional precision. AVstudio (also known as AVgator Studio) is a powerful HTML5 GUI editor that enables developers of all levels to create, customize, and manage rich interfaces for control systems. Whether you prefer a cloud-based platform or a compiled desktop solution, AVstudio adapts to your workflow with seamless cross-platform compatibility and robust feature sets.","permalink":"/avstudio-docs/documentation/Introduction/"},{"id":"documentation/user-interface/3-1-main-dashboard/3-1-main-dashboard","title":"Main Dashboard Overview","description":"The Main Dashboard is the first screen you\u2019ll see after logging into AVstudio. It gives you a snapshot of your projects, templates, and settings. This overview will walk you through each area of the interface so you can navigate and manage your work with confidence.","permalink":"/avstudio-docs/documentation/user-interface/3-1-main-dashboard/"},{"id":"documentation/user-interface/3-11-media-assets/3-11-media-assets","title":"Media Assets Overview","description":"The Media Assets panel is where you can upload and manage images, fonts, and audio files for use in your AVstudio project.","permalink":"/avstudio-docs/documentation/user-interface/3-11-media-assets/"},{"id":"knowledge-base/multilanguage/multilanguage","title":"Multi-Language Implementation Guide","description":"Before We Start","permalink":"/avstudio-docs/knowledge-base/multilanguage/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-6-page-actions/4-4-6-page-actions","title":"Page Actions","description":"The Page Actions section allows you to define automatic or manual behaviors that are triggered when a page loads, exits, or responds to a specific event. These actions help power automation, control signals, and data exchange inside your AVstudio project.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-6-page-actions/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-7-page-background/4-4-7-page-background","title":"Page Background","description":"The Page Background section allows you to customize the visual background of the page. You can use a solid color or set a background image from either your media library or an external URL. Additional options let you control blur, opacity, and image positioning.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-7-page-background/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-page-properties","title":"Page Properties","description":"This article provides an overview of all the page-level settings available in AVstudio. These settings define how each page behaves, looks, and connects to other parts of your project. You can access all of them from the left-hand panel when a page is open in the editor.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/"},{"id":"documentation/user-interface/3-5-pages/3-5-pages","title":"Pages Overview","description":"The Pages section in AVstudio is where you manage the main views of your project. From selecting layout paradigms to configuring signal-based navigation, this interface helps you create, edit, and organize the pages that structure your application.","permalink":"/avstudio-docs/documentation/user-interface/3-5-pages/"},{"id":"documentation/getting-started/2-4-password-recovery/2-4-password-recovery","title":"Password Recovery","description":"If you\'ve lost access to your AVstudio account or can\'t remember your password, this guide will walk you through the password reset process.","permalink":"/avstudio-docs/documentation/getting-started/2-4-password-recovery/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-9-project-css/4-4-9-project-css","title":"Project CSS","description":"The Project CSS section allows you to define and manage custom CSS that applies globally across your AVstudio project. This gives you more control over the appearance of your layout, especially when visual configuration options are not enough or when you want to apply consistent branding across all pages.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-9-project-css/"},{"id":"documentation/user-interface/3-3-project-dashboard/3-3-project-dashboard","title":"Project Dashboard Overview","description":"The Project Dashboard is where you manage your individual projects in AVstudio. It gives you access to project-specific actions like previewing, building, cloning, deleting, and modifying settings \u2014 all within a single view.","permalink":"/avstudio-docs/documentation/user-interface/3-3-project-dashboard/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-10-project-media-library/4-4-10-project-media-library","title":"Project Media Library","description":"The Project Media Library is where you can manage all media assets used in your AVstudio project. This includes background images, icons, UI illustrations, logos, and any other visual content that will be referenced across pages or containers.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-10-project-media-library/"},{"id":"documentation/user-interface/3-4-project-settings/3-4-project-settings","title":"Project Settings Overview","description":"The Project Settings panel is where you configure key properties of your AVstudio project \u2014 from the project name and theme to environment-specific build settings and connector integrations.","permalink":"/avstudio-docs/documentation/user-interface/3-4-project-settings/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-8-project-theme/4-4-8-project-theme","title":"Project Theme","description":"The Project Theme section allows you to define global design settings that apply across your entire project. These include a shared background and universal styling variables like primary colors, text colors, and border radius. Setting your theme properly ensures consistency, simplifies styling, and makes it easier to update your project visually in the future.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-8-project-theme/"},{"id":"documentation/user-interface/3-8-project-variables/3-8-project-variables","title":"Project Variables Overview","description":"The Project Variables section in AVstudio lets you define and manage custom variables that store dynamic values. These variables can be used to control logic, respond to signals, and trigger actions across your project. With support for default values, signal feedback, and formatter functions, project variables give you flexible control over your application\u2019s behavior.","permalink":"/avstudio-docs/documentation/user-interface/3-8-project-variables/"},{"id":"documentation/working-with-projects/4-2-setting-up-project-settings/4-2-setting-up-project-settings","title":"Setting Up Project Settings","description":"After creating your project, the next step is to configure the settings that define how it behaves, builds, and connects. This guide walks you through how to open the project settings panel and configure key fields like environment setup, debug mode, signal IDs, connectors, and dataset access.","permalink":"/avstudio-docs/documentation/working-with-projects/4-2-setting-up-project-settings/"},{"id":"documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-2-size/4-4-4-2-size","title":"Size","description":"The Size section controls how much space the container uses on the page and how spacing behaves inside it. This is where you manage layout structure using either Default or Manual sizing, along with element spacing and padding.","permalink":"/avstudio-docs/documentation/working-with-projects/4-4-page-properties/4-4-4-container-options/4-4-4-2-size/"},{"id":"documentation/user-interface/3-6-subpages/3-6-subpages","title":"Subpages Overview","description":"The Subpages section in AVstudio allows you to create supporting views that complement your main pages. Subpages follow the same layout paradigms as pages and are ideal for building modular, reusable screen components within your project.","permalink":"/avstudio-docs/documentation/user-interface/3-6-subpages/"},{"id":"documentation/getting-started/2-1-system-requirements/2-1-system-requirements","title":"System Requirements","description":"This article outlines the hardware, software, and network requirements needed to run AVstudio smoothly. Whether you\'re using the cloud-based SAAS platform or the compiled GUI environment, make sure your setup meets the following system specifications.","permalink":"/avstudio-docs/documentation/getting-started/2-1-system-requirements/"},{"id":"documentation/user-interface/3-2-user-profile-dashboard/3-2-user-profile-dashboard","title":"User Profile Dashboard Overview","description":"From the AVstudio main dashboard, clicking the profile icon in the upper-right corner gives you access to account-related actions like managing your profile or switching accounts. This page covers what you\u2019ll see and do in the User Profile Dashboard.","permalink":"/avstudio-docs/documentation/user-interface/3-2-user-profile-dashboard/"},{"id":"documentation/getting-started/2-2-user-registration-and-account-setup/2-2-user-registration-and-account-setup","title":"User Registration and Account Setup","description":"Start your journey with AVstudio by setting up a secure and personalized account. This guide walks you through registration, verification, and initial setup so you can begin building interfaces in minutes. \ud83d\ude80","permalink":"/avstudio-docs/documentation/getting-started/2-2-user-registration-and-account-setup/"},{"id":"documentation/working-with-projects/working-with-projects","title":"Working with Projects","description":"This section introduces everything you need to know about managing projects in AVstudio. Whether you\'re creating your first layout, editing an existing setup, or configuring advanced project settings, you\'ll find helpful guides here.","permalink":"/avstudio-docs/documentation/working-with-projects/"}],"unlisted":false}}')}}]);